const parseJsonString = (value) => {
  const cleaned = value
    .trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();

  return JSON.parse(cleaned);
};

let raw = $json.output ?? $json.text ?? $json.response ?? $json;

if (typeof raw === 'string') {
  raw = parseJsonString(raw);
}

if (raw && typeof raw === 'object' && raw.output && typeof raw.output === 'object') {
  raw = raw.output;
}

if (typeof raw === 'string') {
  raw = parseJsonString(raw);
}

if (raw && typeof raw === 'object') {
  return [{ json: raw }];
}

throw new Error('Workflow tidak menghasilkan object JSON yang valid.');

const source = $node["Scoring Docs Evidence"].json ?? {};
const item = $input.first();

const parseJsonString = (value) => {
  const cleaned = String(value)
    .trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
  return JSON.parse(cleaned);
};

let raw = item.json?.text ?? item.json?.response ?? item.json?.output ?? item.json;
if (typeof raw === 'string') {
  raw = parseJsonString(raw);
}
if (!raw || typeof raw !== 'object') {
  throw new Error('Basic LLM Chain1 tidak menghasilkan JSON scoring yang valid.');
}

const aiConfidence = Number(Math.max(0, Math.min(1, Number.parseFloat(String(raw.ai_confidence ?? source.ai_confidence ?? 0))))).toFixed(3);
const requirementId = source.requirement_id;
const categoryId = source.category_id;
const fileName = source.file_name || 'document-uploaded-file';

return [{
  json: {
    ...source,
    ai_confidence: Number(aiConfidence),
    ai_scoring_reason: String(raw.reason ?? '').trim(),
    upload_request: {
      method: 'POST',
      path: `/evidence/categories/${categoryId}/documents`,
      formData: {
        requirement_id: requirementId,
        ai_confidence: aiConfidence
      },
      binary_field: 'document'
    },
    curl_preview: `curl --location -g 'https://experientially-unchallenging-amelie.ngrok-free.dev/api/v1/evidence/categories/${categoryId}/documents' \\\n--header 'Authorization: Bearer REPLACE_WITH_USER_TOKEN' \\\n--form 'requirement_id="${requirementId}"' \\\n--form 'document=@"/${fileName}"' \\\n--form 'ai_confidence="${aiConfidence}"'`
  },
  binary: $node["Scoring Docs Evidence"].binary
}];

const webhook = $node["Evidence Vault"];
const source = webhook.json ?? {};
const body = source.body ?? {};
const binarySource = webhook.binary ?? {};
const document = binarySource.document ?? Object.values(binarySource)[0];
if (!document) {
  throw new Error('Form-data `document` wajib dikirim pada webhook Evidence Vault.');
}

const requirementId = String(body.requirement_id ?? '').trim().toUpperCase();
if (!requirementId) {
  throw new Error('Form-data `requirement_id` wajib dikirim pada webhook Evidence Vault.');
}

const categories = Array.isArray($json?.data) ? $json.data : [];
const category = categories.find((item) => Array.isArray(item.requirements) && item.requirements.some((req) => String(req.requirement_id ?? '').toUpperCase() === requirementId));
if (!category) {
  throw new Error(`requirement_id ${requirementId} tidak ditemukan pada evidence categories.`);
}

const requirement = category.requirements.find((req) => String(req.requirement_id ?? '').toUpperCase() === requirementId);

return [{
  json: {
    requirement_id: requirementId,
    category_id: String(category.category_id ?? category.code ?? requirementId.split('-')[0]).toUpperCase(),
    category_code: String(category.code ?? category.category_id ?? '').toUpperCase(),
    category_name: category.name ?? '',
    category_weight: Number(category.weight ?? 0),
    requirement_name: requirement?.name ?? '',
    requirement_description: requirement?.description ?? '',
    requirement_sort_order: Number(requirement?.sort_order ?? 0),
    provided_ai_confidence: String(body.ai_confidence ?? '').trim(),
    file_name: document.fileName ?? '',
    mime_type: document.mimeType ?? ''
  },
  binary: {
    document
  }
}];

const source = $node["Resolve Requirement Context"].json ?? {};
const document = $node["Resolve Requirement Context"].binary?.document;
if (!document) {
  throw new Error('Form-data `document` wajib dikirim pada webhook Evidence Vault.');
}

const requirementId = String(source.requirement_id ?? '').trim().toUpperCase();
const prompt = [
  `Anda menilai bukti kategori ${source.category_name || source.category_id || '-' } untuk GreenTrust Passport.`,
  requirementId ? `Requirement target: ${requirementId} - ${source.requirement_name || ''}.` : 'Requirement target belum dikirim.',
  source.requirement_description ? `Deskripsi requirement: ${source.requirement_description}` : '',
  'Analisis gambar yang diunggah dan nilai seberapa kuat gambar ini mendukung requirement target.',
  'Kembalikan JSON valid saja dengan schema berikut:',
  '{"image_summary":"","visible_text":[],"visible_objects":[],"document_type_guess":"","evidence_relevance":"","ai_confidence":0}',
  'Aturan:',
  '- image_summary: 1-3 kalimat ringkas terkait isi gambar.',
  '- visible_text: array string teks yang benar-benar terlihat jika ada.',
  '- visible_objects: array string objek utama yang relevan.',
  '- document_type_guess: tebakan jenis dokumen/foto.',
  '- evidence_relevance: alasan singkat keterkaitan gambar terhadap requirement.',
  '- ai_confidence: angka 0 sampai 1, wajib 3 digit desimal. Contoh 0.873.',
  '- Skor tinggi jika bukti visual sangat jelas dan relevan; skor rendah jika ambigu, blur, atau tidak mendukung requirement.',
  '- Jangan kembalikan markdown atau teks di luar JSON.'
].filter(Boolean).join('\n');

return [{
  json: {
    ...source,
    file_name: source.file_name ?? document.fileName ?? '',
    mime_type: source.mime_type ?? document.mimeType ?? '',
    provided_requirement_id: requirementId,
    provided_ai_confidence: String(source.provided_ai_confidence ?? '').trim(),
    alibaba_request: {
      model: 'qwen-vl-plus',
      response_format: { type: 'json_object' },
      messages: [
        {
          role: 'system',
          content: 'You are a precise evidence analyst. Return valid JSON only.'
        },
        {
          role: 'user',
          content: [
            {
              type: 'text',
              text: prompt
            },
            {
              type: 'image_url',
              image_url: {
                url: `data:${document.mimeType};base64,${document.data}`
              }
            }
          ]
        }
      ]
    }
  },
  binary: {
    document
  }
}];

const source = $node["Prepare Image Vision Request"].json ?? {};
const document = $node["Prepare Image Vision Request"].binary?.document;
if (!document) {
  throw new Error('Binary document hilang sebelum proses scoring image evidence.');
}

const rawContent = $json?.choices?.[0]?.message?.content ?? $json?.output_text ?? $json?.content ?? $json;
const parseJsonString = (value) => {
  const cleaned = String(value)
    .trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
  return JSON.parse(cleaned);
};

let vision = rawContent;
if (typeof vision === 'string') {
  vision = parseJsonString(vision);
}
if (!vision || typeof vision !== 'object') {
  throw new Error('Alibaba vision tidak mengembalikan object JSON yang valid.');
}

const visibleText = Array.isArray(vision.visible_text) ? vision.visible_text : [];
const aiSummary = String(vision.image_summary ?? '').trim();
const evidenceRelevance = String(vision.evidence_relevance ?? '').trim();
const providedRequirementId = String(source.provided_requirement_id ?? '').trim().toUpperCase();
const categoryId = providedRequirementId.split('-')[0] || 'BB';

let aiConfidence = Number.parseFloat(String(vision.ai_confidence ?? ''));
if (!Number.isFinite(aiConfidence)) {
  aiConfidence = 0;
}
aiConfidence = Math.max(0, Math.min(1, aiConfidence));
aiConfidence = Number(aiConfidence.toFixed(3));

const confidenceBand = aiConfidence >= 0.8 ? 'high' : aiConfidence >= 0.6 ? 'medium' : 'low';

return [{
  json: {
    category_id: categoryId,
    category_name: 'Bahan Baku & Sourcing',
    category_weight: 20,
    source_type: 'image_vision',
    provided_requirement_id: providedRequirementId || '',
    requirement_id: providedRequirementId || '',
    ai_confidence: aiConfidence,
    confidence_band: confidenceBand,
    ai_summary: aiSummary || evidenceRelevance || 'Analisis gambar berhasil dibuat.',
    ocr_excerpt: visibleText.slice(0, 8).join(' | ').slice(0, 500),
    file_name: source.file_name ?? '',
    mime_type: source.mime_type ?? '',
    vision_analysis: vision
  },
  binary: {
    document
  }
}];

const webhook = $node["Evidence Vault"];
const source = webhook.json ?? {};
const body = source.body ?? {};
const binarySource = webhook.binary ?? {};
const document = binarySource.document ?? Object.values(binarySource)[0];
if (!document) {
  throw new Error('Form-data `document` wajib dikirim pada webhook Bahan Baku & Sourcing.');
}

const requirements = [
  {
    id: 'BB-001',
    name: 'Nota / invoice pembelian bahan baku',
    description: 'Dokumen bukti pembelian bahan baku dari supplier, dapat berupa nota, invoice, atau bukti transaksi pembelian.',
    keywords: ['nota', 'invoice', 'faktur', 'pembelian', 'supplier', 'qty', 'jumlah', 'harga', 'total', 'transaksi'],
    preferImage: false,
    preferText: true
  },
  {
    id: 'BB-002',
    name: 'Surat jalan dari supplier',
    description: 'Dokumen pengiriman dari supplier yang membuktikan asal dan alur distribusi bahan baku.',
    keywords: ['surat jalan', 'delivery order', 'pengiriman', 'supplier', 'diterima', 'tujuan', 'tanggal kirim', 'alamat kirim'],
    preferImage: false,
    preferText: true
  },
  {
    id: 'BB-003',
    name: 'Foto atau profil supplier',
    description: 'Dokumentasi visual atau profil singkat supplier untuk memperkuat bukti sumber bahan baku.',
    keywords: ['supplier', 'pemasok', 'profil', 'profile', 'toko', 'alamat', 'kontak', 'foto'],
    preferImage: true,
    preferText: false
  }
];

const pages = Array.isArray($json.pages) ? $json.pages : [];
const ocrText = pages.map((page) => page.markdown ?? page.text ?? '').join('\n\n').trim();
const normalizedText = `${String(document.fileName ?? '')}\n${ocrText}`.toLowerCase();
const mimeType = String(document.mimeType ?? '').toLowerCase();
const providedRequirementId = String(body.requirement_id ?? '').trim().toUpperCase();
const providedConfidence = Number.parseFloat(String(body.ai_confidence ?? '').trim());
const categoryId = providedRequirementId.split('-')[0] || 'BB';

const evaluate = (requirement) => {
  const matches = requirement.keywords.filter((keyword) => normalizedText.includes(keyword));
  let score = 0.2 + matches.length * 0.1;

  if (requirement.preferImage && mimeType.startsWith('image/')) score += 0.08;
  if (requirement.preferText && ocrText.length >= 40) score += 0.08;
  if (ocrText.length >= 120) score += 0.04;
  if (!ocrText && requirement.preferImage && mimeType.startsWith('image/')) score += 0.06;

  return {
    ...requirement,
    matches,
    score: Math.max(0.05, Math.min(0.98, Number(score.toFixed(2))))
  };
};

const ranked = requirements.map(evaluate).sort((left, right) => right.score - left.score);
const bestMatch = ranked[0];
const selectedMatch = providedRequirementId
  ? ranked.find((item) => item.id === providedRequirementId)
  : bestMatch;

if (!selectedMatch) {
  throw new Error(`requirement_id ${providedRequirementId} tidak valid untuk kategori ${categoryId}.`);
}

let aiConfidence = selectedMatch.score;
if (Number.isFinite(providedConfidence) && providedConfidence >= 0 && providedConfidence <= 1) {
  aiConfidence = Number(providedConfidence.toFixed(2));
} else if (providedRequirementId && bestMatch.id !== providedRequirementId && bestMatch.score - selectedMatch.score >= 0.12) {
  aiConfidence = Math.max(0.2, Number((selectedMatch.score - 0.15).toFixed(2)));
}

const confidenceBand = aiConfidence >= 0.8 ? 'high' : aiConfidence >= 0.6 ? 'medium' : 'low';
const summarySignals = selectedMatch.matches.length > 0 ? selectedMatch.matches.slice(0, 5).join(', ') : 'indikasi teks/visual masih minim';

return [{
  json: {
    category_id: categoryId,
    category_name: 'Bahan Baku & Sourcing',
    category_weight: 20,
    source_type: 'ocr_document',
    provided_requirement_id: providedRequirementId || '',
    requirement_id: selectedMatch.id,
    requirement_name: selectedMatch.name,
    requirement_description: selectedMatch.description,
    suggested_requirement_id: bestMatch.id,
    suggested_requirement_name: bestMatch.name,
    ai_confidence: Number(aiConfidence.toFixed(2)),
    confidence_band: confidenceBand,
    ai_summary: `Dokumen paling dekat dengan ${selectedMatch.id} (${selectedMatch.name}). Sinyal utama: ${summarySignals}.`,
    ocr_excerpt: ocrText.slice(0, 500),
    file_name: document.fileName ?? '',
    mime_type: document.mimeType ?? '',
    scoring: {
      best_match: {
        requirement_id: bestMatch.id,
        score: bestMatch.score,
        matches: bestMatch.matches
      },
      selected_match: {
        requirement_id: selectedMatch.id,
        score: Number(aiConfidence.toFixed(2)),
        matches: selectedMatch.matches
      },
      candidates: ranked.map((item) => ({
        requirement_id: item.id,
        score: item.score,
        matches: item.matches
      }))
    }
  },
  binary: {
    document
  }
}];

const source = $node["Scoring Image Evidence"].json ?? {};
const item = $input.first();

const parseJsonString = (value) => {
  const cleaned = String(value)
    .trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
  return JSON.parse(cleaned);
};

let raw = item.json?.text ?? item.json?.response ?? item.json?.output ?? item.json;
if (typeof raw === 'string') {
  raw = parseJsonString(raw);
}
if (!raw || typeof raw !== 'object') {
  throw new Error('Basic LLM Chain tidak menghasilkan JSON scoring yang valid.');
}

const aiConfidence = Number(Math.max(0, Math.min(1, Number.parseFloat(String(raw.ai_confidence ?? source.ai_confidence ?? 0))))).toFixed(3);
const requirementId = source.requirement_id;
const categoryId = source.category_id;
const fileName = source.file_name || 'document-uploaded-file';

return [{
  json: {
    ...source,
    ai_confidence: Number(aiConfidence),
    ai_scoring_reason: String(raw.reason ?? '').trim(),
    upload_request: {
      method: 'POST',
      path: `/evidence/categories/${categoryId}/documents`,
      formData: {
        requirement_id: requirementId,
        ai_confidence: aiConfidence
      },
      binary_field: 'document'
    },
    curl_preview: `curl --location -g 'https://experientially-unchallenging-amelie.ngrok-free.dev/api/v1/evidence/categories/${categoryId}/documents' \\\n--header 'Authorization: Bearer REPLACE_WITH_USER_TOKEN' \\\n--form 'requirement_id="${requirementId}"' \\\n--form 'document=@"/${fileName}"' \\\n--form 'ai_confidence="${aiConfidence}"'`
  },
  binary: $node["Scoring Image Evidence"].binary
}];

